// Frontend API client for Community (CRA-safe)
const BASE_URL =
  (process.env.REACT_APP_API_BASE || "").replace(/\/$/, "") || "http://localhost:4000";

export async function list({ city, tab, cursor, limit = 20 }) {
  const params = new URLSearchParams();
  if (city) params.set("city", city);
  if (tab) params.set("tab", String(tab).toLowerCase());
  if (cursor) params.set("cursor", String(cursor));
  params.set("limit", String(limit));

  const r = await fetch(`${BASE_URL}/api/community?${params.toString()}`);
  if (!r.ok) throw new Error("Failed to load");
  return r.json(); // { items, nextCursor }
}

export async function create({ text, city, media = [], quoteOf = null, hashtags = [] }) {
  // If any media entry has a _file, upload it first
  const mediaOut = [];
  for (const m of media) {
    if (m && m._file) {
      const url = await upload(m._file);
      mediaOut.push({ url, type: m._file.type, name: m._file.name });
    } else if (m) {
      mediaOut.push({ url: m.url, type: m.type, name: m.name });
    }
  }

  const r = await fetch(`${BASE_URL}/api/community`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, city, media: mediaOut, quoteOf, hashtags }),
  });
  if (!r.ok) throw new Error("Create failed");
  return r.json(); // saved post
}

export async function like(id) {
  await fetch(`${BASE_URL}/api/community/${id}/like`, { method: "POST" });
}

export async function repost(id) {
  await fetch(`${BASE_URL}/api/community/${id}/repost`, { method: "POST" });
}

export async function reply(id, { text }) {
  const r = await fetch(`${BASE_URL}/api/community/${id}/reply`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text }),
  });
  if (!r.ok) throw new Error("Reply failed");
  return r.json();
}

export async function upload(file) {
  const fd = new FormData();
  fd.append("file", file);
  const r = await fetch(`${BASE_URL}/api/upload`, { method: "POST", body: fd });
  if (!r.ok) throw new Error("Upload failed");
  const { url } = await r.json();
  return `${BASE_URL}${url.startsWith("/") ? "" : "/"}${url}`;
}
